changeSet.sql:
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'estado_carrito') THEN
        CREATE TYPE estado_carrito AS ENUM ('ACTIVO','PROCESANDO','COMPLETADO','ABANDONADO');
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'estado_pago') THEN
        CREATE TYPE estado_pago AS ENUM ('PENDIENTE','COMPLETADO','FALLIDO','REEMBOLSADO');
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'metodo_pago') THEN
        CREATE TYPE metodo_pago AS ENUM ('TARJETA_CREDITO','TARJETA_DEBITO','TRANSFERENCIA','EFECTIVO');
    END IF;
END $body$;

changeSet.rollback:
DROP TYPE IF EXISTS estado_carrito;
DROP TYPE IF EXISTS estado_pago;
DROP TYPE IF EXISTS metodo_pago;

changeSet.sql:
CREATE INDEX IF NOT EXISTS idx_carrito_cliente_estado ON carrito(cliente_id, estado);
CREATE INDEX IF NOT EXISTS idx_carrito_item_carrito   ON carrito_item(carrito_id);
CREATE INDEX IF NOT EXISTS idx_pago_pedido            ON pago(pedido_id);
CREATE INDEX IF NOT EXISTS idx_pago_estado            ON pago(estado);

changeSet.rollback:
DROP INDEX IF EXISTS idx_carrito_cliente_estado;
DROP INDEX IF EXISTS idx_carrito_item_carrito;
DROP INDEX IF EXISTS idx_pago_pedido;
DROP INDEX IF EXISTS idx_pago_estado;

