INSERT INTO producto (nombre, descripcion, precio, stock)
SELECT 'Laptop Pro 15', 'Laptop de alto rendimiento con 16GB RAM', 1299.99, 20
WHERE NOT EXISTS (SELECT 1 FROM producto WHERE nombre = 'Laptop Pro 15');

